      linked++;
    }catch(e){log.push('patch fail '+ref.id);}
  }
  summary='еҲҶжһҗе®ҢжҲҗгҖӮиҷ•зҗҶ '+refById.length+' зӯҶеј•з”ЁиіҮж–ҷ,жҠҪ '+total_ent+' еҖӢе…·еҗҚеҜҰй«”(жӯЈиҰҸеҢ–еҺ»йҮҚеҫҢ '+canon_ct+' еҖӢ),ж–°е»ә DB08 зҙҖйҢ„ '+created+' зӯҶ,'+linked+' зӯҶе·ІиЈңе°ҚжҮүжЁҷзұӨ+еҲҶжһҗеӮҷиЁ»гҖӮ';
}catch(err){ summary='еҲҶжһҗжЈ’йҢҜиӘӨ: '+(err&&err.message||err); }
const nowTW=new Date().toLocaleString('zh-TW',{timeZone:'Asia/Taipei'});
